<?php
$pageTitle='Manage Users';require __DIR__.'/../includes/header.php';require_role('admin');$rows=$pdo->query('SELECT id,name,email,phone,role,status,created_at FROM users ORDER BY created_at DESC')->fetchAll();
?>
<div class="container py-5"><h1 class="section-title">Manage Users</h1><div class="card shadow-soft table-card mt-4"><div class="table-responsive"><table class="table align-middle"><thead class="table-light"><tr><th>User</th><th>Role</th><th>Status</th><th>Joined</th><th>Action</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><strong><?=e($r['name'])?></strong><br><small><?=e($r['email'])?> • <?=e($r['phone'])?></small></td><td><?=e(role_label($r['role']))?></td><td><?=status_badge($r['status'])?></td><td><?=date('d M Y',strtotime($r['created_at']))?></td><td><?php if($r['role']!=='admin'):?><form method="post" action="<?=url('actions/admin_action.php')?>"><?=csrf_field()?><input type="hidden" name="type" value="user"><input type="hidden" name="id" value="<?=$r['id']?>"><input type="hidden" name="action" value="<?=$r['status']==='active'?'block':'activate'?>"><button class="btn btn-sm <?=$r['status']==='active'?'btn-outline-danger':'btn-outline-success'?>"><?=$r['status']==='active'?'Block':'Activate'?></button></form><?php endif;?></td></tr><?php endforeach;?></tbody></table></div></div></div>
